"use client";

import { AnalysisResult } from "@/types/analysis";
import { SummaryCard } from "./SummaryCard";
import { ArchitectureView } from "./ArchitectureView";
import { motion } from "framer-motion";

interface AnalysisDashboardProps {
    data: AnalysisResult | null;
    isLoading: boolean;
    error: string | null;
}

export function AnalysisDashboard({ data, isLoading, error }: AnalysisDashboardProps) {
    if (isLoading) {
        return (
            <div className="w-full max-w-5xl mx-auto mt-12 text-center">
                <div className="inline-block w-16 h-16 border-4 border-primary border-t-transparent rounded-full animate-spin mb-4" />
                <p className="text-muted-foreground animate-pulse">Analyzing codebase... This may take a minute.</p>
            </div>
        );
    }

    if (error) {
        return (
            <div className="w-full max-w-2xl mx-auto mt-12 p-6 glass-card border-red-500/50 rounded-xl text-center">
                <p className="text-red-400 mb-2">Analysis Failed</p>
                <p className="text-muted-foreground">{error}</p>
            </div>
        );
    }

    if (!data) return null;

    return (
        <div className="w-full max-w-6xl mx-auto mt-12 px-4 pb-20">
            <SummaryCard data={data} />
            <ArchitectureView diagram={data.architecture} />

            {/* Quality Analysis Grid */}
            <motion.div
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 0.4 }}
                className="grid grid-cols-1 md:grid-cols-2 gap-6"
            >
                <h3 className="text-xl font-semibold col-span-full mb-2">Quality Recommendations</h3>
                {data.qualityAnalysis.map((item, i) => (
                    <div key={i} className="glass-card p-6 rounded-xl border-l-4 border-l-primary">
                        <div className="flex justify-between items-start mb-2">
                            <h4 className="font-medium text-primary">{item.category}</h4>
                        </div>
                        <p className="text-sm font-medium text-red-300 mb-2">Issue: {item.issue}</p>
                        <p className="text-sm text-muted-foreground">Fix: {item.recommendation}</p>
                    </div>
                ))}
            </motion.div>
        </div>
    );
}
